@code {
    [CascadingParameter] private TreeView<T>.TreeViewContext? Context { get; set; }

    [Parameter] public TreeView<T>.TreeViewItem<T> Item { get; set; } = default!;
    [Parameter] public int Level { get; set; }
    [Parameter] public int PosInSet { get; set; } = 1;
    [Parameter] public int SetSize { get; set; } = 1;
    [Parameter] public bool ShowCheckboxes { get; set; }
    [Parameter] public bool Expandable { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnItemClick { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnItemCheck { get; set; }

    [Parameter] public bool CascadeCheck { get; set; }
    [Parameter] public bool MultiSelect { get; set; }
    // When true (the tree default), clicking anywhere on a PARENT row toggles its
    // expansion in addition to selecting it; false keeps the chevron as the sole
    // expand trigger. Threaded down so every level shares the tree's mode.
    [Parameter] public bool ExpandOnRowClick { get; set; } = true;
    // The set of currently-selected NODE instances (reference-identity comparer, owned by
    // the parent TreeView). Selection is by identity, not Value, so a container node with a
    // null/duplicate Value highlights only itself — see TreeView._selectedNodes (GH #350).
    [Parameter] public HashSet<TreeView<T>.TreeViewItem<T>>? SelectedNodes { get; set; }
    [Parameter] public RenderFragment<TreeView<T>.TreeViewItem<T>>? NodeTemplate { get; set; }
    [Parameter] public Func<TreeView<T>.TreeViewItem<T>, Task<List<TreeView<T>.TreeViewItem<T>>>>? LoadChildren { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnExpandChanged { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnSelectionChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("group focus-visible:outline-none", Class);

    // Roving tabindex (WAI-ARIA tree pattern): the tree keeps exactly one node —
    // the active one — in the tab sequence; every other node carries -1 and is
    // reached with the arrow keys. Without a cascaded tree context (node rendered
    // standalone) fall back to the legacy root-level behavior.
    private bool _isFocused;
    private string TabIndex => Context is not null
        ? Context.Tree.GetTabIndex(Item).ToString()
        : ((_isFocused || Level == 0) ? "0" : "-1");
    private string ExpandLabel => EffectiveExpanded ? "Collapse" : "Expand";

    // Deterministic id for keyboard-navigation focus targeting; local fallback
    // keeps standalone nodes valid HTML.
    private readonly string _fallbackId = LumeoIds.New("treenode");
    private string NodeId => Context?.Tree.GetNodeId(Item) ?? _fallbackId;

    private bool HasLoadedChildren => Item.Children is { Count: > 0 };

    // Expansion as rendered: the item's own state, plus any search-forced
    // expansion tracked by the parent tree while a filter is active.
    private bool EffectiveExpanded => Context?.Tree.IsEffectivelyExpanded(Item) ?? Item.IsExpanded;

    // Children as rendered: when a search filter is active only the visible
    // subset is rendered; otherwise all loaded children.
    private IReadOnlyList<TreeView<T>.TreeViewItem<T>> VisibleChildren
        => Context is not null
            ? Context.Tree.GetVisibleChildren(Item)
            : (IReadOnlyList<TreeView<T>.TreeViewItem<T>>?)Item.Children ?? [];

    private bool ShowExpandChevron =>
        HasLoadedChildren ||
        (LoadChildren is not null && !Item.IsLeaf && !Item.ChildrenLoaded);

    // Identity match: SelectedNodes uses a reference-equality comparer, so this is true
    // only for the exact clicked node — never for a sibling that shares Item.Value.
    private bool IsSelected => SelectedNodes?.Contains(Item) == true;

    private string? AriaExpanded => ShowExpandChevron
        ? EffectiveExpanded.ToString().ToLowerInvariant()
        : null;

    private string NodeClass
    {
        get
        {
            var parts = new List<string>
            {
                "group/row flex items-center gap-1.5 py-1 px-2 rounded-md transition-colors text-sm group-focus-visible:ring-[1.5px] group-focus-visible:ring-ring group-focus-visible:ring-offset-1",
                Item.IsDisabled ? "opacity-50 cursor-not-allowed text-muted-foreground" : "cursor-pointer hover:bg-accent/50"
            };
            if (IsSelected && !Item.IsDisabled)
                parts.Add("bg-accent text-accent-foreground");
            return string.Join(" ", parts);
        }
    }

    // Single ChevronDown that rotates -90deg when collapsed; smooth like Accordion.
    // Brightens from muted → foreground when the label row is hovered (group-hover/row),
    // an integrated affordance that needs no background block of its own.
    private string ChevronClass => Cx.Join(
        "h-4 w-4 shrink-0 text-muted-foreground group-hover/row:text-foreground transition-transform duration-200",
        Cx.When(!EffectiveExpanded, "-rotate-90"));

    private string IconClass =>
        Item.IsDisabled
            ? "h-4 w-4 text-muted-foreground opacity-50 shrink-0"
            : "h-4 w-4 text-muted-foreground shrink-0";

    private void HandleFocus()
    {
        _isFocused = true;
        // Focus arrived directly (mouse/Tab) — keep the roving tabindex in sync.
        Context?.Tree.SetActive(Item);
    }

    private void HandleBlur()
    {
        _isFocused = false;
    }

    // Expansion has TWO parts that a row click must keep decoupled (see HandleClick):
    //   1. the state flip on THIS node instance — done SYNCHRONOUSLY, before any await, so a
    //      selection-driven rebuild (a controlled/immutable tree, @key'd by instance) snapshots the
    //      new IsExpanded off the LIVE node instead of a stale/disposed one (the round-4 guarantee).
    //   2. the lazy child-load — an await that may be slow or throw. It is returned as the tail Task
    //      so the caller chooses to await it inline (the chevron / keyboard, whose only job is to
    //      expand) or drain it isolated from selection (the row click).
    // Children only render once actually loaded (the HasLoadedChildren gate), so flipping IsExpanded
    // ahead of the load never paints an empty expanded branch.
    private Task ToggleExpand()
    {
        if (EffectiveExpanded)
        {
            Item.IsExpanded = false;
            return OnExpandChanged.InvokeAsync(Item);
        }

        // Mark expanded NOW (synchronous state mutation on the live instance) — the (possibly slow
        // or throwing) child-load below must not gate this, or a selection-driven rebuild would
        // snapshot the still-collapsed node.
        Item.IsExpanded = true;

        if (LoadChildren is not null && !Item.ChildrenLoaded && !Item.IsLeaf && !HasLoadedChildren)
        {
            Item.IsLoading = true;
            // Snapshot this node's structural path NOW — synchronously, before the row-click
            // selection callbacks can rebuild Items — so a load FAILURE can collapse the CURRENT
            // rendered instance even after a controlled/immutable rebuild replaced THIS one
            // (round-8: the rollback must reach the fresh @key'd node, not just the stale instance).
            var pathAtExpand = Context?.Tree.GetIndexPath(Item);
            return LoadChildrenThenNotifyAsync(pathAtExpand);
        }

        return OnExpandChanged.InvokeAsync(Item);
    }

    // The awaited tail of a lazy expansion: fetch the children, mirror a fully-checked parent's
    // state onto them (rc.42), then raise OnExpandChanged. IsLoading is always cleared (finally) so
    // a slow OR throwing loader never leaves the node stuck spinning. On loader FAILURE the just-
    // applied expansion is rolled back to collapsed (round-7) before the exception propagates — the
    // children never materialized, so leaving IsExpanded=true would strand the row aria-expanded=true
    // with a down chevron over an empty branch (and the next click would COLLAPSE it instead of
    // retrying the load). ChildrenLoaded stays false, so the row remains retryable. The exception
    // still propagates exactly as before — the chevron/keyboard path lets it surface; the row click
    // drains it isolated (HandleClick) AFTER the rollback, so the collapse survives either path and
    // the already-applied selection (round-5) is untouched.
    private async Task LoadChildrenThenNotifyAsync(IReadOnlyList<int>? pathAtExpand)
    {
        StateHasChanged();
        // The node the loaded children attach to. Defaults to THIS instance; re-resolved to the
        // currently-rendered node below if a controlled/immutable rebuild replaced it mid-load.
        var target = Item;
        try
        {
            var loaded = await LoadChildren!(Item);

            // Attach to the CURRENTLY rendered node (round-8 rollback's SUCCESS mirror, round-9
            // finding 1): a row click on a lazy parent starts THIS load BEFORE its selection
            // callbacks run; a controlled/immutable parent can rebuild Items inside
            // SelectedValuesChanged while the loader is still pending, disposing this @key'd node and
            // re-creating it around a FRESH instance (carrying the optimistic IsExpanded=true).
            // Assigning the children to the STALE Item would then leave the visible fresh node
            // expanded-but-empty. Re-resolve the current node by the value-verified path (the SAME
            // mechanism RollbackFailedExpansion uses on failure) and attach to THAT. Null (node
            // vanished / ambiguous identity) or no tree context (standalone node) → the local
            // instance is the best target.
            target = Context?.Tree.ResolveExpansionTarget(Item, pathAtExpand) ?? Item;
            target.Children = loaded;
            target.ChildrenLoaded = true;
            // The fresh node already carries IsExpanded=true (the rebuild copied it); assert it so a
            // rebuild that dropped the flag still reveals the just-loaded children on the one click.
            target.IsExpanded = true;
            // Clear the spinner on the RESOLVED node too (a rebuild may have copied IsLoading=true
            // onto the fresh instance); the finally below only clears the stale Item.
            target.IsLoading = false;

            // rc.42: if the parent was fully checked before lazy-load, cascade
            // that state to the freshly-loaded children. Without this, a
            // checked parent would expand to reveal unchecked children — a
            // visibly broken tri-state. Indeterminate parents leave loaded
            // children at their default (unchecked) state, then we
            // recompute the parent to reflect actual loaded counts.
            if (target.IsChecked && !target.IsIndeterminate)
            {
                CascadeChecked(target.Children, true);
            }
            else if (target.IsIndeterminate)
            {
                // All loaded children default to unchecked → parent is no
                // longer indeterminate if nothing is checked. Recompute.
                var anyChecked = target.Children.Any(c => c.IsChecked || c.IsIndeterminate);
                if (!anyChecked)
                {
                    target.IsIndeterminate = false;
                    target.IsChecked = false;
                }
            }
        }
        catch
        {
            // Lazy load failed: ToggleExpand already flipped IsExpanded=true synchronously (the
            // round-4 guarantee) but no children arrived. Roll the expansion back to collapsed so
            // the row returns to a retryable state (ChildrenLoaded is still false, so a later click
            // re-runs the loader) instead of showing aria-expanded=true / a down chevron over an
            // empty branch. Re-render this node so the chevron + aria reflect the collapse; then
            // re-throw so the error still surfaces on the chevron/keyboard path and is drained
            // isolated on the row-click path. Selection stays intact (applied by the caller).
            Item.IsExpanded = false;
            // The line above collapses only THIS (possibly stale) instance. If a controlled/
            // immutable parent rebuilt Items inside the selection callbacks while the loader was
            // in flight, this instance was replaced by a fresh @key'd one that still carries the
            // optimistic IsExpanded=true; route the rollback through the tree so it re-resolves and
            // collapses the CURRENT rendered node too (round-8). A standalone node with no tree
            // context keeps the local collapse above.
            if (Context is not null)
                Context.Tree.RollbackFailedExpansion(Item, pathAtExpand);
            StateHasChanged();
            throw;
        }
        finally
        {
            Item.IsLoading = false;
        }

        // Notify for the RESOLVED node so HandleExpandChanged binds pending selections / derives
        // tri-state against the instance that actually holds the freshly-loaded children (this may
        // be the fresh @key'd node after a controlled rebuild, not the stale Item).
        await OnExpandChanged.InvokeAsync(target);
    }

    // Click semantic (documented): clicking the label ROW always SELECTS the node (and raises
    // OnItemClick). By DEFAULT (ExpandOnRowClick=true) a click on a PARENT row — one that has,
    // or can lazily load, children — ALSO toggles its expansion, so the whole row is the
    // expand/collapse target (larger hit area / touch target; the VS Code file-tree pattern).
    // Leaf rows only select. A lazy parent loads its children on row click exactly like the
    // chevron does (via ToggleExpand). Set ExpandOnRowClick=false to opt back into chevron-only
    // expansion: the row then selects but never expands. The chevron button remains an
    // expand/collapse trigger in BOTH modes and stops propagation, so it toggles without
    // selecting; keyboard expansion (ArrowRight/Left) is unchanged. A selection-modifier click
    // (Ctrl/Meta/Shift — used to build a multi-selection) only mutates selection, never
    // expansion, so folders don't flap open while the user is range/toggle-selecting.
    private async Task HandleClick(MouseEventArgs e)
    {
        if (Item.IsDisabled) return;

        // Flip expansion on the LIVE node instance SYNCHRONOUSLY — before the selection callbacks —
        // but do NOT gate the selection on the lazy child-load.
        //
        // Round-4 (stale instance): the selection callbacks can rebuild Items (a controlled/
        // immutable tree); because every node is @key'd by its instance, that rebuild DISPOSES this
        // component and re-creates it around a fresh node. ToggleExpand mutates Item.IsExpanded
        // SYNCHRONOUSLY before it returns its tail Task, so the rebuild snapshots the new expansion
        // off THIS instance and carries it onto the fresh one (a toggle deferred until AFTER the
        // awaits would land on the stale/disposed instance).
        //
        // Round-5 (selection vs loader): that tail may await LoadChildren, which can be slow or
        // throw. Awaiting it HERE (as the previous reorder did) would delay the selection behind a
        // slow loader and KILL it outright on a throwing one — the exception would escape before
        // OnItemClick/OnSelectionChanged ever ran. So the selection callbacks fire NEXT, ungated by
        // the load, and the tail is drained isolated afterwards — mirroring the chevron, whose load
        // lives in its own handler and never gates a selection.
        var expandTail = ExpandOnRowClick && Expandable && ShowExpandChevron && !IsSelectionModifier(e)
            ? ToggleExpand()
            : Task.CompletedTask;

        await OnItemClick.InvokeAsync(Item);
        await OnSelectionChanged.InvokeAsync(Item);

        await DrainExpansionIsolated(expandTail);
    }

    // Drain the lazy-expansion tail AFTER the selection has been applied, absorbing a loader failure
    // so it can neither roll back the (already-committed) selection nor surface as an unhandled
    // circuit exception. ToggleExpand's own finally has already cleared IsLoading, so the node never
    // sticks spinning; the row's contract is to SELECT — surfacing a background branch-load failure
    // is the chevron/keyboard path's job, not the click's.
    private static async Task DrainExpansionIsolated(Task expandTail)
    {
        try { await expandTail; }
        catch (Exception) { /* a lazy-loader failure must not break the completed selection */ }
    }

    // A modifier held during the click is a selection gesture (extend/toggle a multi-selection),
    // not a navigation intent, so row-click expansion is suppressed for it.
    private static bool IsSelectionModifier(MouseEventArgs e)
        => e.CtrlKey || e.MetaKey || e.ShiftKey;

    private async Task HandleCheck(bool value)
    {
        if (Item.IsDisabled) return;
        Item.IsChecked = value;
        if (Item.IsIndeterminate && !value)
            Item.IsIndeterminate = false;
        await OnItemCheck.InvokeAsync(Item);
    }

    // WAI-ARIA tree keyboard pattern. Expand/collapse mutations stay here (the
    // node owns its item); pure focus movement is delegated to the parent tree,
    // which knows the flattened visible order.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // Page-scroll for the focus-moving keys is suppressed synchronously in
        // JS (see OnAfterRenderAsync) — the former render-time _preventKey flag
        // lagged one event, so the first ArrowDown/Up/Home/End still scrolled
        // the page while focus also moved (Codex P2).
        switch (e.Key)
        {
            case "ArrowDown":
            case "ArrowUp":
            case "Home":
            case "End":
                if (Context is not null)
                    await Context.Tree.HandleNavigationKeyAsync(Item, e.Key);
                break;

            case "ArrowRight":
                if (ShowExpandChevron && Expandable && !EffectiveExpanded)
                    await ToggleExpand();
                else if (Context is not null)
                    await Context.Tree.HandleNavigationKeyAsync(Item, e.Key); // move into first child
                break;

            case "ArrowLeft":
                if (EffectiveExpanded)
                {
                    Item.IsExpanded = false;
                    await OnExpandChanged.InvokeAsync(Item);
                }
                else if (Context is not null)
                {
                    await Context.Tree.HandleNavigationKeyAsync(Item, e.Key); // move to parent
                }
                break;

            case "Enter":
            case " ":
                if (!Item.IsDisabled)
                {
                    if (ShowCheckboxes)
                    {
                        if (Item.IsIndeterminate)
                        {
                            Item.IsIndeterminate = false;
                            Item.IsChecked = true;
                        }
                        else
                        {
                            Item.IsChecked = !Item.IsChecked;
                        }
                        await OnItemCheck.InvokeAsync(Item);
                    }
                    else
                    {
                        await OnItemClick.InvokeAsync(Item);
                        await OnSelectionChanged.InvokeAsync(Item);
                    }
                }
                break;
        }
    }

    /// <summary>Cascades a check state to a freshly-loaded subtree (rc.42).
    /// Used after <see cref="LoadChildren"/> resolves so children inherit a
    /// fully-checked parent's state instead of staying unchecked.</summary>
    private static void CascadeChecked(List<TreeView<T>.TreeViewItem<T>> items, bool value)
    {
        foreach (var item in items)
        {
            item.IsChecked = value;
            item.IsIndeterminate = false;
            if (item.Children is { Count: > 0 })
            {
                CascadeChecked(item.Children, value);
            }
        }
    }

    // Suppress page scroll for the focus-moving keys synchronously in JS,
    // against the id the DOM actually carries (a consumer `id` in the splat
    // wins over NodeId). Re-registered when that id changes; prerender-safe.
    private string? _pdRegisteredId;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        var id = LumeoIds.Effective(AdditionalAttributes, NodeId);
        if (_pdRegisteredId == id) return;
        try
        {
            if (_pdRegisteredId is not null)
                await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId);
            await Interop.RegisterPreventDefaultKeys(id, new[]
            {
                new Lumeo.Services.PreventDefaultKeyRule("ArrowDown"),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowUp"),
                new Lumeo.Services.PreventDefaultKeyRule("Home"),
                new Lumeo.Services.PreventDefaultKeyRule("End"),
            });
            _pdRegisteredId = id;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (_pdRegisteredId is null) return;
        try { await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
